steps.details:
Add the following CSS to your main stylesheet (e.g., `style.css`):

css
:root {
    --background-color: #ffffff;
    --text-color: #333333;
    --primary-color: #007bff;
    --secondary-background: #f8f9fa;
    --border-color: #dee2e6;
}

.dark-theme {
    --background-color: #1a1a1a;
    --text-color: #e0e0e0;
    --primary-color: #8ab4f8;
    --secondary-background: #2c2c2c;
    --border-color: #444444;
}

body {
    background-color: var(--background-color);
    color: var(--text-color);
    transition: background-color 0.3s ease, color 0.3s ease;
}

/* Example for a button or link */
a {
    color: var(--primary-color);
}

button {
    background-color: var(--primary-color);
    color: var(--background-color);
    border: 1px solid var(--primary-color);
}

.card {
    background-color: var(--secondary-background);
    border: 1px solid var(--border-color);
    color: var(--text-color);
}

Insert the following HTML snippet into your `index.html` or header component:

html
<button id="theme-toggle" aria-label="Toggle dark mode">
    <span class="icon">☀️</span>
</button>


Optionally, add basic CSS for the toggle button:

css
#theme-toggle {
    background: none;
    border: none;
    font-size: 1.5em;
    cursor: pointer;
    padding: 10px;
    border-radius: 5px;
    transition: background-color 0.3s ease;
}

#theme-toggle:hover {
    background-color: var(--secondary-background);
}

.dark-theme #theme-toggle .icon {
    content: '🌙'; /* Change icon in dark mode if using CSS content */
}

Create a new JavaScript file (e.g., `script.js`) or add to an existing one:

javascript
document.addEventListener('DOMContentLoaded', () => {
    const themeToggle = document.getElementById('theme-toggle');
    const body = document.body;

    // Function to set the theme
    function setTheme(theme) {
        if (theme === 'dark') {
            body.classList.add('dark-theme');
            if (themeToggle) themeToggle.querySelector('.icon').textContent = '🌙';
        } else {
            body.classList.remove('dark-theme');
            if (themeToggle) themeToggle.querySelector('.icon').textContent = '☀️';
        }
        localStorage.setItem('theme', theme);
    }

    // Get saved theme from localStorage or default to system preference
    const savedTheme = localStorage.getItem('theme');
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

    if (savedTheme) {
        setTheme(savedTheme);
    } else if (prefersDark) {
        setTheme('dark');
    } else {
        setTheme('light');
    }

    // Event listener for the toggle button
    if (themeToggle) {
        themeToggle.addEventListener('click', () => {
            const currentTheme = body.classList.contains('dark-theme') ? 'dark' : 'light';
            const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
            setTheme(newTheme);
        });
    }
});


Ensure `script.js` is linked in your `index.html` before the closing `</body>` tag:

html
<script src="script.js"></script>

